import{_ as r,I as o,o as a,c as n,a4 as e,b as i,w as d,a as l,J as c,a5 as h}from"./chunks/framework.CoAJCMjA.js";const k=JSON.parse('{"title":"专辑模块 · 功能介绍","description":"","frontmatter":{},"headers":[],"relativePath":"album.md","filePath":"album.md"}'),b={name:"album.md"};function g(p,t,u,m,A,_){const s=o("Mermaid");return a(),n("div",null,[t[1]||(t[1]=e('<h1 id="专辑模块-·-功能介绍" tabindex="-1">专辑模块 · 功能介绍 <a class="header-anchor" href="#专辑模块-·-功能介绍" aria-label="Permalink to “专辑模块 · 功能介绍”">​</a></h1><h2 id="_1-模块概述" tabindex="-1">1. 模块概述 <a class="header-anchor" href="#_1-模块概述" aria-label="Permalink to “1. 模块概述”">​</a></h2><p><strong>专辑模块</strong>负责曲库中专辑的浏览、曲目播放、封面与元数据维护，以及多艺术家合辑的展示。核心入口为 Web 前端的 <strong><code>/albums</code></strong>（侧栏「专辑」）与 <strong><code>/albums/:id</code></strong>（专辑详情）。</p><p>与艺术家模块不同，专辑<strong>没有</strong>独立的管理后台页；管理员能力（专辑刮削、曲目元数据编辑、空专辑删除等）集成在 <strong>专辑详情页</strong> 与 <strong><a href="/music-free-site/music.html">音乐管理</a></strong> 的刮削 Tab 中。</p>',4)),(a(),i(h,null,{default:d(()=>[c(s,{id:"mermaid-12",class:"mermaid",graph:"flowchart%20TB%0A%20%20subgraph%20user%20%5B%E7%94%A8%E6%88%B7%E7%AB%AF%20%2Falbums%5D%0A%20%20%20%20L%5B%E4%B8%93%E8%BE%91%E5%88%97%E8%A1%A8%5D%0A%20%20%20%20D%5B%E4%B8%93%E8%BE%91%E8%AF%A6%E6%83%85%5D%0A%20%20%20%20T%5B%E6%9B%B2%E7%9B%AE%E5%88%97%E8%A1%A8%20%2F%20%E6%92%AD%E6%94%BE%5D%0A%20%20end%0A%20%20subgraph%20admin%20%5B%E7%AE%A1%E7%90%86%E5%91%98%E8%83%BD%E5%8A%9B%5D%0A%20%20%20%20A%5B%E5%8C%B9%E9%85%8D%E5%B9%B6%E5%88%AE%E5%89%8A%E4%B8%93%E8%BE%91%5D%0A%20%20%20%20E%5B%E7%BC%96%E8%BE%91%E5%8D%95%E6%9B%B2%E5%85%83%E6%95%B0%E6%8D%AE%5D%0A%20%20%20%20S%5B%E5%8D%95%E6%9B%B2%E5%88%AE%E5%89%8A%5D%0A%20%20end%0A%20%20subgraph%20plugins%20%5BWASM%20%E6%8F%92%E4%BB%B6%20GetAlbumInfo%5D%0A%20%20%20%20MB%5BMusicBrainz%5D%0A%20%20%20%20NE%5B%E7%BD%91%E6%98%93%E4%BA%91%5D%0A%20%20%20%20QQ%5BQQ%20%E9%9F%B3%E4%B9%90%5D%0A%20%20%20%20SP%5BSpotify%5D%0A%20%20%20%20LF%5BLast.fm%5D%0A%20%20end%0A%20%20subgraph%20data%20%5B%E6%95%B0%E6%8D%AE%5D%0A%20%20%20%20AL%5B(albums)%5D%0A%20%20%20%20AA%5B(album_artists)%5D%0A%20%20%20%20SO%5B(songs)%5D%0A%20%20end%0A%20%20L%20--%3E%20D%0A%20%20D%20--%3E%20T%0A%20%20D%20--%3E%20A%0A%20%20D%20--%3E%20E%0A%20%20D%20--%3E%20S%0A%20%20A%20--%3E%20plugins%0A%20%20plugins%20--%3E%20AL%0A%20%20E%20--%3E%20SO%0A%20%20SO%20--%3E%20AA%0A%20%20AA%20--%3E%20AL%0A"})]),fallback:d(()=>[...t[0]||(t[0]=[l(" Loading... ",-1)])]),_:1})),t[2]||(t[2]=e(`<p>扫描本地或 WebDAV 媒体源后，系统按文件标签中的 <strong>专辑名 + 主艺术家</strong> 聚合生成 <code>albums</code> 记录；曲目通过 <code>songs.album_id</code> 归属专辑，并通过 <strong><code>album_artists</code></strong> 维护「参与艺术家」集合（合辑、群星盘等）。</p><h2 id="_2-访问与权限" tabindex="-1">2. 访问与权限 <a class="header-anchor" href="#_2-访问与权限" aria-label="Permalink to “2. 访问与权限”">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>路径</th><th>用户</th></tr></thead><tbody><tr><td>专辑列表</td><td><code>/albums</code></td><td>所有登录用户</td></tr><tr><td>专辑详情</td><td><code>/albums/:id</code></td><td>所有登录用户</td></tr><tr><td>播放、收藏、下载曲目</td><td>详情页曲目行</td><td>登录用户（下载依服务端策略）</td></tr><tr><td>匹配并刮削专辑</td><td>详情页</td><td>管理员</td></tr><tr><td>编辑曲目元数据 / 单曲刮削</td><td>详情页曲目行</td><td>管理员</td></tr><tr><td>删除空专辑</td><td>列表或艺术家详情中的专辑卡片</td><td>管理员</td></tr><tr><td>批量曲目刮削</td><td><code>/admin/music</code> → 音乐刮削</td><td>管理员</td></tr></tbody></table><h2 id="_3-专辑浏览" tabindex="-1">3. 专辑浏览 <a class="header-anchor" href="#_3-专辑浏览" aria-label="Permalink to “3. 专辑浏览”">​</a></h2><h3 id="_3-1-专辑列表" tabindex="-1">3.1 专辑列表 <a class="header-anchor" href="#_3-1-专辑列表" aria-label="Permalink to “3.1 专辑列表”">​</a></h3><ul><li><strong>展示</strong>：卡片网格，含封面、专辑名、主艺术家、年份、曲目数。</li><li><strong>搜索</strong>：按专辑名（及关联信息）模糊匹配；支持 URL 查询参数 <code>q</code>、<code>page</code>、<code>pageSize</code>。</li><li><strong>分页</strong>：默认每页 20 条。</li><li><strong>按艺术家筛选</strong>：内部 API 支持 <code>artistId</code> 参数（艺术家详情页跳转专辑时使用）。</li><li><strong>空状态</strong>：未扫描媒体库时提示「扫描音乐库后即可在此浏览专辑」。</li></ul><h3 id="_3-2-专辑详情" tabindex="-1">3.2 专辑详情 <a class="header-anchor" href="#_3-2-专辑详情" aria-label="Permalink to “3.2 专辑详情”">​</a></h3><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td>头部</td><td>封面、专辑名、主艺术家、年份、流派、总时长、曲目数</td></tr><tr><td>参与艺术家</td><td>来自 <code>album_artists</code> 的艺术家头像条（最多展示 5 个，超出折叠为「+N」）；点击跳转 <code>/artists/:id</code></td></tr><tr><td>操作</td><td><strong>播放全部</strong>；管理员可见 <strong>匹配并刮削</strong></td></tr><tr><td>曲目列表</td><td>曲序、标题、码率/品质、格式、收藏、时长；点击行播放</td></tr></tbody></table><p><strong>曲目列表操作</strong>（管理员）：</p><table tabindex="0"><thead><tr><th>操作</th><th>说明</th></tr></thead><tbody><tr><td>编辑元数据</td><td>弹窗修改标题、艺术家、专辑等，保存后触发 <code>album_artists</code> 重算</td></tr><tr><td>刮削元数据</td><td>对单首曲目调用 <code>ScraperSong</code> 链路（与音乐管理批量刮削相同引擎）</td></tr><tr><td>下载</td><td>以原始文件流下载到本地（保留服务端建议文件名）</td></tr></tbody></table><p>所有用户可对单曲使用 <strong>收藏</strong>（心形按钮）。</p><h3 id="_3-3-封面展示" tabindex="-1">3.3 封面展示 <a class="header-anchor" href="#_3-3-封面展示" aria-label="Permalink to “3.3 封面展示”">​</a></h3><ul><li>OpenSubsonic 封面 ID：<strong><code>al-{albumId}</code></strong>。</li><li>Web 前端通过 <code>getCoverArt</code> 拉取封面图；无封面时显示占位图标。</li><li>专辑刮削保存后，封面 key 存于 <code>albums.cover_art</code>（<code>sha256-...</code> 文件位于 <code>music.cover_path</code>）。</li></ul><p><strong>占位专辑名</strong>：<code>Unknown Album</code>（大小写不敏感）不分配 <code>al-</code> 封面 ID，且<strong>不支持</strong>专辑级刮削。</p><h2 id="_4-参与艺术家-album-artists" tabindex="-1">4. 参与艺术家（album_artists） <a class="header-anchor" href="#_4-参与艺术家-album-artists" aria-label="Permalink to “4. 参与艺术家（album_artists）”">​</a></h2><h3 id="_4-1-作用" tabindex="-1">4.1 作用 <a class="header-anchor" href="#_4-1-作用" aria-label="Permalink to “4.1 作用”">​</a></h3><p>一张专辑可能对应多位艺术家（合作专辑、合辑、原声带等）。除 <strong>主艺术家</strong>外，系统记录了多位艺术家与专辑的参与关系，使得：</p><ul><li>专辑详情页展示「参与艺术家」头像条；</li><li>各参与艺术家的详情页也能列出该专辑。</li></ul><h2 id="_5-专辑匹配并刮削-管理员" tabindex="-1">5. 专辑匹配并刮削（管理员） <a class="header-anchor" href="#_5-专辑匹配并刮削-管理员" aria-label="Permalink to “5. 专辑匹配并刮削（管理员）”">​</a></h2><h3 id="_5-1-能做什么" tabindex="-1">5.1 能做什么 <a class="header-anchor" href="#_5-1-能做什么" aria-label="Permalink to “5.1 能做什么”">​</a></h3><p>在专辑详情页点击 <strong>「匹配并刮削」</strong>：</p><ol><li>后端使用专辑的 <strong>主艺术家名 + 专辑名</strong> 调用已启用、支持 <strong>album</strong> 编排维度的插件（<code>GetAlbumInfo</code>）。</li><li>汇总各插件返回的 <strong>候选列表</strong>（每个插件至多一条），弹窗展示封面预览、专辑名、艺术家、发行日期、简介、来源。</li><li>管理员选择候选并 <strong>保存确认</strong> 后写入数据库。</li></ol><p><strong>特点</strong>：预览阶段 <strong>不写库</strong>；须人工确认，避免误匹配。</p><h3 id="_5-2-限制与插件" tabindex="-1">5.2 限制与插件 <a class="header-anchor" href="#_5-2-限制与插件" aria-label="Permalink to “5.2 限制与插件”">​</a></h3><ul><li><strong>不支持刮削</strong>：专辑名为 <code>Unknown Album</code> 占位。</li></ul><p>插件需在 <strong>插件管理</strong>（<code>/admin/plugin</code>）启用，且刮削编排包含 <strong>album</strong> 字段。</p><h3 id="_5-4-与曲目刮削的关系" tabindex="-1">5.4 与曲目刮削的关系 <a class="header-anchor" href="#_5-4-与曲目刮削的关系" aria-label="Permalink to “5.4 与曲目刮削的关系”">​</a></h3><table tabindex="0"><thead><tr><th>维度</th><th>专辑「匹配并刮削」</th><th>详情页单曲「刮削」 / 音乐管理批量刮削</th></tr></thead><tbody><tr><td>插件能力</td><td><code>GetAlbumInfo</code></td><td><code>ScraperSong</code>（+ 可选 <code>GetCover</code> / <code>GetLyrics</code>）</td></tr><tr><td>作用对象</td><td>整张专辑元数据与封面</td><td>单首歌曲标签与封面</td></tr><tr><td>入口</td><td><code>/albums/:id</code></td><td>曲目行按钮或 <code>/admin/music</code></td></tr><tr><td>确认方式</td><td>弹窗选候选后保存</td><td>单曲刮削多为自动应用；批量可勾选强制重刮</td></tr></tbody></table><p>二者互补：先批量修正曲目，再对整张专辑统一补封面与发行信息。</p><h2 id="_6-管理员维护" tabindex="-1">6. 管理员维护 <a class="header-anchor" href="#_6-管理员维护" aria-label="Permalink to “6. 管理员维护”">​</a></h2><h3 id="_6-1-删除专辑" tabindex="-1">6.1 删除专辑 <a class="header-anchor" href="#_6-1-删除专辑" aria-label="Permalink to “6.1 删除专辑”">​</a></h3><ul><li><strong>条件</strong>：管理员 + 专辑下 <strong>歌曲数为 0</strong>。</li><li><strong>入口</strong>：专辑列表卡片删除按钮，或艺术家详情页中的空专辑卡片。</li><li><strong>说明</strong>：仅删除数据库中的专辑记录，<strong>不删除</strong>磁盘音频文件。</li></ul><h3 id="_6-2-编辑曲目元数据" tabindex="-1">6.2 编辑曲目元数据 <a class="header-anchor" href="#_6-2-编辑曲目元数据" aria-label="Permalink to “6.2 编辑曲目元数据”">​</a></h3><p>通过详情页 <strong>编辑</strong> 打开 <code>SongMetadataEditDialog</code>，可修改曲名、艺术家、专辑归属等。保存后：</p><ul><li>更新 <code>songs</code> 表；</li><li>必要时触发旧/新专辑的 <code>album_artists</code> 重算；</li><li>刷新当前专辑详情展示。</li></ul><hr><h2 id="_7-opensubsonic-与第三方客户端" tabindex="-1">7. OpenSubsonic 与第三方客户端 <a class="header-anchor" href="#_7-opensubsonic-与第三方客户端" aria-label="Permalink to “7. OpenSubsonic 与第三方客户端”">​</a></h2><p>Music Free 向 Subsonic/OpenSubsonic 客户端暴露标准专辑接口：</p><table tabindex="0"><thead><tr><th>接口</th><th>用途</th></tr></thead><tbody><tr><td><code>getAlbum</code></td><td>专辑元数据 + 曲目列表</td></tr><tr><td><code>getAlbumList</code> / <code>getAlbumList2</code></td><td>按类型列出专辑（最新、随机、按年、按流派、收藏等）</td></tr><tr><td><code>getMusicDirectory</code></td><td>以 <code>id=专辑ID</code> 浏览专辑内曲目</td></tr><tr><td><code>getCoverArt</code></td><td><code>id=al-{albumId}</code> 获取封面</td></tr></tbody></table><p><strong>getAlbumList 类型示例</strong>（<code>type</code> 参数）：<code>newest</code>、<code>random</code>、<code>alphabeticalByName</code>、<code>alphabeticalByArtist</code>、<code>frequent</code>、<code>recent</code>、<code>starred</code>、<code>byYear</code>（需 <code>fromYear</code>/<code>toYear</code>）、<code>byGenre</code>（需 <code>genre</code>）等。</p><p>Navidrome 兼容 REST（实验性）：<code>GET /api/album</code>、<code>GET /api/album/:id</code>。</p><hr><h2 id="_8-典型工作流" tabindex="-1">8. 典型工作流 <a class="header-anchor" href="#_8-典型工作流" aria-label="Permalink to “8. 典型工作流”">​</a></h2><h3 id="_8-1-浏览与播放" tabindex="-1">8.1 浏览与播放 <a class="header-anchor" href="#_8-1-浏览与播放" aria-label="Permalink to “8.1 浏览与播放”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>扫描媒体源 → /albums 浏览</span></span>
<span class="line"><span>    → 进入详情 → 播放全部或点击单曲</span></span>
<span class="line"><span>    → OpenSubsonic 客户端亦可通过 getAlbum 播放</span></span></code></pre></div><h3 id="_8-2-补全专辑封面与信息" tabindex="-1">8.2 补全专辑封面与信息 <a class="header-anchor" href="#_8-2-补全专辑封面与信息" aria-label="Permalink to “8.2 补全专辑封面与信息”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/admin/plugin 启用 MusicBrainz / 网易云 等</span></span>
<span class="line"><span>    → /albums/:id → 「匹配并刮削」</span></span>
<span class="line"><span>    → 对比候选封面与发行日期 → 保存确认</span></span></code></pre></div><h3 id="_8-3-整理合辑与多艺人专辑" tabindex="-1">8.3 整理合辑与多艺人专辑 <a class="header-anchor" href="#_8-3-整理合辑与多艺人专辑" aria-label="Permalink to “8.3 整理合辑与多艺人专辑”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>详情页编辑各曲目艺术家归属</span></span>
<span class="line"><span>    → 保存后 album_artists 自动更新</span></span>
<span class="line"><span>    → 参与艺术家头像条与艺术家详情页专辑列表同步</span></span></code></pre></div><h3 id="_8-4-批量修正曲目后再统一专辑" tabindex="-1">8.4 批量修正曲目后再统一专辑 <a class="header-anchor" href="#_8-4-批量修正曲目后再统一专辑" aria-label="Permalink to “8.4 批量修正曲目后再统一专辑”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>/admin/music → 音乐刮削 → 批量处理未刮削曲目</span></span>
<span class="line"><span>    → 回到专辑详情 → 「匹配并刮削」统一封面</span></span></code></pre></div><hr><h2 id="_9-常见问题" tabindex="-1">9. 常见问题 <a class="header-anchor" href="#_9-常见问题" aria-label="Permalink to “9. 常见问题”">​</a></h2><p><strong>Q：列表里没有专辑？</strong><br> A: 确认已配置媒体源并完成扫描；检查歌曲标签是否包含专辑名。</p><p><strong>Q：封面一直是占位图？</strong><br> A: 可对专辑执行「匹配并刮削」；或依赖扫描时从嵌入封面提取（<code>songs</code> 封面回写）。<code>Unknown Album</code> 不会生成封面 ID。</p><p><strong>Q：「匹配并刮削」无候选？</strong><br> A: 检查插件是否启用、是否支持 <code>getAlbumInfo</code>、API 配置是否正确；专辑名勿为占位；查看弹窗警告中的各插件尝试信息。</p><p><strong>Q：参与艺术家显示不全？</strong><br> A: 确认各曲目 <code>artist_id</code> 正确；保存元数据或重扫后会触发重新计算；主艺术家不会重复出现在「参与艺术家」条中。</p><p><strong>Q：删除专辑失败？</strong><br> A: 仅当专辑下 <strong>无歌曲</strong> 时可删；需先将曲目移到其他专辑或删除曲目记录。</p>`,58))])}const B=r(b,[["render",g]]);export{k as __pageData,B as default};
